export function buildMotorcycleImageKey(brand, model) {
  const normalize = (value) => String(value || "").toLowerCase().replace(/&/g, "and").replace(/[^a-z0-9]/g, "");
  const normalizeBrandForMatch = (b) => {
    const raw = String(b || "").trim();
    const upper = raw.toUpperCase();
    const aliases = {
      "DUCATI": "Ducati",
      "MOTO MORINI": "Moto Morini",
      "MOTOMORINI": "Moto Morini",
      "HOND": "Honda",
      "VESPA": "Vespa",
      "VOGE": "Voge",
      "HARLEY DAVIDSON": "Harley-Davidson",
      "HARLEY-DAVIDSON": "Harley-Davidson"
    };
    return aliases[upper] || raw;
  };
  const normalizeModelForMatch = (b, m) => {
    const raw = String(m || "").toLowerCase().replace(/\([^)]*\)/g, "");
    if (!raw) return "";
    const tokens = raw.replace(/\b(20\d{2})\b/g, "").replace(/[()]/g, " ").split(/[\s/-]+/).filter(Boolean);
    const drop = new Set(["adventure","adv","gsa","rally","rallye","touring","tour","edition","special","se","sp","gt","gts","rs","xr","dct","abs","pro","premium","sport","sporting","ltd","limited","classic","ultra","deluxe","automatic","auto","transmission"]);
    const brandKey = normalize(b);
    if (brandKey === "bmw") {
      const joined = tokens.join("");
      if (joined.includes("r1300gs") || joined.includes("r1250gs")) return "r1250gs";
      if (joined.includes("f900gs")) return "f900gs";
      if (joined.includes("f750gs") || joined.includes("f850gs")) return "f850gs";
      if (joined.includes("r1300rt") || joined.includes("r1250rt")) return "r1250rt";
    }
    if (brandKey === "honda") {
      if (tokens.includes("africa") && tokens.includes("twin")) return "africatwin";
    }
    if (brandKey === "ducati") {
      if (tokens.includes("multistrada")) return "multistrada";
    }
    const normalized = tokens.filter((t) => !drop.has(t)).join("");
    return normalized || tokens.join("");
  };
  const canonicalBrand = normalizeBrandForMatch(brand);
  const baseModel = normalizeModelForMatch(canonicalBrand, model);
  return `${normalize(canonicalBrand)}|${normalize(baseModel)}`;
}
